sections.code_example:
# Map each word to its length
words = ["cat", "elephant", "ox"]
lengths = {word: len(word) for word in words}
print(lengths)

# Square each number (number -> square)
squares = {n: n ** 2 for n in range(1, 6)}
print(squares)

# Filter: keep only entries where value > 3
long_words = {word: len(word) for word in words if len(word) > 3}
print(long_words)

# Filter an existing dict — keep only positive values
scores = {"Alice": 95, "Bob": -5, "Carol": 82, "Dan": -12}
passing = {k: v for k, v in scores.items() if v > 0}
print(passing)

# zip() two lists into a dict
keys = ["name", "age", "city"]
values = ["Alice", 30, "Paris"]
person = {k: v for k, v in zip(keys, values)}
print(person)

